(()=>{const progress=document.querySelector('[data-reading-progress]');const progressBar=document.querySelector('[data-reading-progress-bar]');const source=document.querySelector('[data-reading-progress-source]');if(progress && progressBar && source){let progressFrame=0;const updateProgress=()=>{progressFrame=0;const rect=source.getBoundingClientRect();const total=source.offsetHeight-window.innerHeight;if(total<=0){progress.hidden=true;return;}const current=Math.min(Math.max(-rect.top,0),total);const value=Math.max(0,Math.min(100,(current/total)*100));progress.hidden=false;progressBar.style.width=`${value}%`;};const scheduleProgressUpdate=()=>{if(progressFrame){return;}progressFrame=window.requestAnimationFrame(updateProgress);};updateProgress();document.addEventListener('scroll',scheduleProgressUpdate,{passive:true});window.addEventListener('resize',scheduleProgressUpdate,{passive:true});}document.querySelectorAll('[data-copy-url]').forEach((button)=>{button.addEventListener('click',async()=>{const url=button.getAttribute('data-copy-url')|| '';const defaultLabel=button.getAttribute('data-copy-default')|| 'Copy';const successLabel=button.getAttribute('data-copy-success')|| 'Copied';const label=button.querySelector('span:last-child');const defaultTitle=button.getAttribute('title')|| defaultLabel;try{if(navigator.clipboard && window.isSecureContext){await navigator.clipboard.writeText(url);}else{window.prompt('Copiaza acest link:',url);}if(label){label.textContent=successLabel;}button.setAttribute('title',successLabel);window.setTimeout(()=>{if(label){label.textContent=defaultLabel;}button.setAttribute('title',defaultTitle);},1800);}catch(error){button.setAttribute('title',defaultTitle);}});});document.querySelectorAll('[data-print-page]').forEach((button)=>{button.addEventListener('click',()=>{window.print();});});})();
